package allstar

import (
	"fmt"
	"strings"

	"typefox.dev/fastbelt/generator"
)

// EmitGoSource returns Go source code for a function that constructs an
// equivalent RuntimeATN without calling CreateATN.  The generated function
// can be compiled into any package that imports the allstar package.
//
//   pkgName  – Go package name for the generated file (e.g. "myparser")
//   funcName – name of the generated constructor function
//   importPath – import path of the allstar package (e.g. "typefox.dev/fastbelt/parser/allstar")
func EmitGoSource(pkgName, funcName, importPath string, rtn *RuntimeATN) string {
	// Index each state pointer to its position in rtn.States.
	idx := make(map[*RuntimeATNState]int, len(rtn.States))
	for i, s := range rtn.States {
		idx[s] = i
	}

	root := generator.NewNode()
	root.AppendLine("// Code generated by fastbelt. DO NOT EDIT.")
	root.AppendLine()
	root.AppendLine("package ", pkgName)
	root.AppendLine()
	root.AppendLine(fmt.Sprintf("import allstar %q", importPath))
	root.AppendLine()
	root.AppendLine("func ", funcName, "() *allstar.RuntimeATN {")
	root.Indent(func(body generator.Node) {
		body.AppendLine(fmt.Sprintf("states := make([]*allstar.RuntimeATNState, %d)", len(rtn.States)))

		// Emit state declarations (without transitions so forward refs are fine).
		for i, s := range rtn.States {
			body.AppendLine(fmt.Sprintf("states[%d] = &allstar.RuntimeATNState{", i))
			body.Indent(func(fields generator.Node) {
				fields.AppendLine(fmt.Sprintf("StateNumber: %d,", s.StateNumber))
				fields.AppendLine(fmt.Sprintf("Type: allstar.%s,", atnStateTypeName(s.Type)))
				fields.AppendLine(fmt.Sprintf("Decision: %d,", s.Decision))
				if s.EpsilonOnlyTransitions {
					fields.AppendLine("EpsilonOnlyTransitions: true,")
				}
				if s.RuleName != "" {
					fields.AppendLine(fmt.Sprintf("RuleName: %q,", s.RuleName))
				}
				if s.ProdIdx != 0 {
					fields.AppendLine(fmt.Sprintf("ProdKind: allstar.%s,", productionKindName(s.ProdKind)))
					fields.AppendLine(fmt.Sprintf("ProdIdx: %d,", s.ProdIdx))
				}
			})
			body.AppendLine("}")
		}

		// Emit transitions (states already declared, so pointer refs are valid).
		for i, s := range rtn.States {
			if len(s.Transitions) == 0 {
				continue
			}
			body.AppendLine(fmt.Sprintf("states[%d].Transitions = []allstar.RuntimeTransition{", i))
			body.Indent(func(trans generator.Node) {
				for _, t := range s.Transitions {
					switch at := t.(type) {
					case *RuntimeAtomTransition:
						trans.AppendLine(fmt.Sprintf(
							"&allstar.RuntimeAtomTransition{Target: states[%d], TokenTypeID: %d, CategoryMatches: %s},",
							idx[at.Target], at.TokenTypeID, emitIntSlice(at.CategoryMatches)))
					case *RuntimeEpsilonTransition:
						trans.AppendLine(fmt.Sprintf(
							"&allstar.RuntimeEpsilonTransition{Target: states[%d]},",
							idx[at.Target]))
					case *RuntimeRuleTransition:
						trans.AppendLine(fmt.Sprintf(
							"&allstar.RuntimeRuleTransition{Target: states[%d], FollowState: states[%d]},",
							idx[at.Target], idx[at.FollowState]))
					}
				}
			})
			body.AppendLine("}")
		}

		// DecisionStates slice.
		body.AppendLine(fmt.Sprintf("decisionStates := make([]*allstar.RuntimeATNState, %d)", len(rtn.DecisionStates)))
		for i, ds := range rtn.DecisionStates {
			if ds != nil {
				body.AppendLine(fmt.Sprintf("decisionStates[%d] = states[%d]", i, idx[ds]))
			}
		}

		// DecisionMap.
		body.AppendLine("decisionMap := map[string]*allstar.RuntimeATNState{")
		body.Indent(func(entries generator.Node) {
			for key, s := range rtn.DecisionMap {
				entries.AppendLine(fmt.Sprintf("%q: states[%d],", key, idx[s]))
			}
		})
		body.AppendLine("}")

		body.AppendLine("return &allstar.RuntimeATN{")
		body.Indent(func(fields generator.Node) {
			fields.AppendLine("States:         states,")
			fields.AppendLine("DecisionStates: decisionStates,")
			fields.AppendLine("DecisionMap:    decisionMap,")
		})
		body.AppendLine("}")
	})
	root.AppendLine("}")
	return root.String()
}

func emitIntSlice(s []int) string {
	if len(s) == 0 {
		return "nil"
	}
	parts := make([]string, len(s))
	for i, v := range s {
		parts[i] = fmt.Sprintf("%d", v)
	}
	return "[]int{" + strings.Join(parts, ", ") + "}"
}

func atnStateTypeName(t ATNStateType) string {
	switch t {
	case ATNInvalidType:
		return "ATNInvalidType"
	case ATNBasic:
		return "ATNBasic"
	case ATNRuleStart:
		return "ATNRuleStart"
	case ATNPlusBlockStart:
		return "ATNPlusBlockStart"
	case ATNStarBlockStart:
		return "ATNStarBlockStart"
	case ATNTokenStart:
		return "ATNTokenStart"
	case ATNRuleStop:
		return "ATNRuleStop"
	case ATNBlockEnd:
		return "ATNBlockEnd"
	case ATNStarLoopBack:
		return "ATNStarLoopBack"
	case ATNStarLoopEntry:
		return "ATNStarLoopEntry"
	case ATNPlusLoopBack:
		return "ATNPlusLoopBack"
	case ATNLoopEnd:
		return "ATNLoopEnd"
	default:
		return fmt.Sprintf("ATNStateType(%d)", int(t))
	}
}

func productionKindName(k ProductionKind) string {
	switch k {
	case ProdTerminal:
		return "ProdTerminal"
	case ProdNonTerminal:
		return "ProdNonTerminal"
	case ProdAlternative:
		return "ProdAlternative"
	case ProdAlternation:
		return "ProdAlternation"
	case ProdOption:
		return "ProdOption"
	case ProdRepetition:
		return "ProdRepetition"
	case ProdRepetitionMandatory:
		return "ProdRepetitionMandatory"
	default:
		return fmt.Sprintf("ProductionKind(%d)", int(k))
	}
}
